import { describe, it, expect } from 'vitest';
import type { SpacetimeEvent } from './causal-topology';
import {
  DEFAULT_COSMOLOGICAL_PARAMS,
  hubbleTimeYears,
  hubbleRadius,
  particleHorizonRadius,
  eventHorizonRadius,
  cosmicHorizonMap,
} from './cosmic-horizon';

// ─── Helpers ────────────────────────────────────────────────────────

function makeEvent(id: string, distanceLy: number): SpacetimeEvent {
  return { id, label: id, x: distanceLy, y: 0, z: 0, pLo: 0 };
}

// ─── Tests ──────────────────────────────────────────────────────────

describe('cosmic-horizon', () => {
  describe('DEFAULT_COSMOLOGICAL_PARAMS', () => {
    it('has correct values', () => {
      expect(DEFAULT_COSMOLOGICAL_PARAMS.hubbleConstantKmPerSecPerMpc).toBe(67.4);
      expect(DEFAULT_COSMOLOGICAL_PARAMS.matterDensity).toBe(0.315);
      expect(DEFAULT_COSMOLOGICAL_PARAMS.darkEnergyDensity).toBe(0.685);
      expect(DEFAULT_COSMOLOGICAL_PARAMS.ageOfUniverseYears).toBe(13.8e9);
    });
  });

  describe('hubbleTimeYears', () => {
    it('returns approximately 14.5 billion years', () => {
      const t = hubbleTimeYears();
      expect(t).toBeGreaterThan(14e9);
      expect(t).toBeLessThan(15e9);
    });
  });

  describe('hubbleRadius', () => {
    it('returns approximately 14.5 billion ly at the current epoch', () => {
      const r = hubbleRadius(13.8e9);
      expect(r).toBeGreaterThan(14e9);
      expect(r).toBeLessThan(15e9);
    });
  });

  describe('particleHorizonRadius', () => {
    it('returns approximately 46.5 billion ly at the current epoch', () => {
      const r = particleHorizonRadius(13.8e9);
      expect(r).toBeCloseTo(46.5e9, -9);
    });

    it('returns a smaller horizon at t = 1 billion years', () => {
      const rNow = particleHorizonRadius(13.8e9);
      const rEarly = particleHorizonRadius(1e9);
      expect(rEarly).toBeLessThan(rNow);
    });

    it('returns 0 at t = 0 (no horizon at the Big Bang)', () => {
      expect(particleHorizonRadius(0)).toBe(0);
    });
  });

  describe('eventHorizonRadius', () => {
    it('returns approximately 16.5 billion ly', () => {
      const r = eventHorizonRadius();
      expect(r).toBe(16.5e9);
    });
  });

  describe('cosmicHorizonMap', () => {
    const nearby = makeEvent('proxima', 4);
    const farAway = makeEvent('beyond', 50e9);

    it('classifies a nearby body as inside the horizon', () => {
      const horizon = cosmicHorizonMap([nearby]);
      expect(horizon.bodies[0].insideHorizon).toBe(true);
      expect(horizon.bodiesInsideCount).toBe(1);
      expect(horizon.bodiesOutsideCount).toBe(0);
    });

    it('classifies a 50-billion-ly body as outside the horizon', () => {
      const horizon = cosmicHorizonMap([farAway]);
      expect(horizon.bodies[0].insideHorizon).toBe(false);
      expect(horizon.bodiesInsideCount).toBe(0);
      expect(horizon.bodiesOutsideCount).toBe(1);
    });

    it('horizonFraction is between 0 and 1', () => {
      const horizon = cosmicHorizonMap([nearby, farAway]);
      expect(horizon.horizonFraction).toBeGreaterThanOrEqual(0);
      expect(horizon.horizonFraction).toBeLessThanOrEqual(1);
      expect(horizon.horizonFraction).toBe(0.5);
    });

    it('at very early cosmic time most bodies are outside the horizon', () => {
      const bodies = [
        makeEvent('a', 4),
        makeEvent('b', 100),
        makeEvent('c', 1e6),
        makeEvent('d', 1e9),
        makeEvent('e', 50e9),
      ];
      // At t = 1000 years, particle horizon is tiny
      const horizon = cosmicHorizonMap(bodies, 1000);
      expect(horizon.bodiesOutsideCount).toBeGreaterThan(horizon.bodiesInsideCount);
    });

    it('sets source to GnosisCosmicHorizon', () => {
      const horizon = cosmicHorizonMap([nearby]);
      expect(horizon.source).toBe('GnosisCosmicHorizon');
    });

    it('defaults cosmicTimeYears to age of universe', () => {
      const horizon = cosmicHorizonMap([nearby]);
      expect(horizon.cosmicTimeYears).toBe(13.8e9);
    });
  });
});
